sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {
    if (isLoading) return;
    if (!newValue && newValue !== '0') return;

    var units = parseInt(newValue);
    if (isNaN(units) || units < 0) {
        g_form.showFieldMsg('units_available', 'Units Available cannot be negative.', 'error');
    } else {
        g_form.hideFieldMsg('units_available');
    }
}
